  /**
   * Tính phụ phí theo loại giường (không giường hoặc giường phụ)
   *
   * @param bedType - Loại giường (NO_BED hoặc EXTRA_BED)
   * @param extraAdults - Số người lớn thêm
   * @param childUnder12 - Danh sách tuổi trẻ em dưới 12
   * @param resolvedMealPlan - Loại bữa ăn
   * @param stayDates - Danh sách các đêm lưu trú
   * @param hotelId - ID khách sạn
   * @param roomId - ID phòng
   * @param calendar - Dữ liệu lịch phụ phí
   * @returns Thông tin phụ phí (tổng, chi tiết, trạng thái hợp lệ)
   */
  private calcSurchargeByBedType(
    bedType: SurchargeBedType,
    extraAdults: number,
    childUnder12: number[],
    resolvedMealPlan: MealPlan,
    stayDates: HotelRoomStayDate[],
    hotelId: number,
    roomId: number,
    calendar: SurchargeCalendarMap,
  ) {
    let total = 0;
    let matchedAny = false;
    let missingChildCoverage = false;
    let missingAdultCoverage = false;
    const surcharges: HotelPriceSurcharge[] = [];
    const isExtraBed = bedType === SurchargeBedType.EXTRA_BED;

    stayDates.forEach(stayDate => {
      const dateKey = dayjs(stayDate.stayDate).format('YYYY-MM-DD');
      const rows = this.getCalendarRowsForDate(calendar, hotelId, roomId, dateKey);
      if (!rows.length) {
        if (extraAdults > 0) {
          missingAdultCoverage = true;
        }
        if (childUnder12.length > 0) {
          missingChildCoverage = true;
        }
        return;
      }

      const rowsForMeal = rows.filter(row => row.mealPlan === resolvedMealPlan);
      if (!rowsForMeal.length) {
        if (extraAdults > 0) {
          missingAdultCoverage = true;
        }
        if (childUnder12.length > 0) {
          missingChildCoverage = true;
        }
        return;
      }

      if (extraAdults > 0) {
        const adultRow = this.selectSurchargeRow(rowsForMeal, CustomerType.ADULT, isExtraBed);
        if (!adultRow) {
          missingAdultCoverage = true;
          return;
        }
        const adultTotal = this.calculateCalendarSurchargeAmount(adultRow, stayDate.baseRate, extraAdults);
        if (adultRow && adultTotal > 0) {
          matchedAny = true;
          total += adultTotal;
          surcharges.push({
            stayDate: new Date(stayDate.stayDate),
            mealPlan: resolvedMealPlan,
            type: adultRow.type,
            customerType: adultRow.customerType,
            unitType: adultRow.unitType,
            unitAmount: Number(adultRow.amount),
            quantity: extraAdults,
            total: adultTotal,
          });
        }
      }

      childUnder12.forEach(age => {
        const childRow = this.selectSurchargeRow(rowsForMeal, CustomerType.CHILD, isExtraBed, age);
        if (!childRow) {
          missingChildCoverage = true;
          return;
        }
        const childTotal = this.calculateCalendarSurchargeAmount(childRow, stayDate.baseRate, 1);
        if (childRow && childTotal > 0) {
          matchedAny = true;
          total += childTotal;
          surcharges.push({
            stayDate: new Date(stayDate.stayDate),
            mealPlan: resolvedMealPlan,
            type: childRow.type,
            customerType: childRow.customerType,
            age,
            unitType: childRow.unitType,
            unitAmount: Number(childRow.amount),
            quantity: 1,
            total: childTotal,
          });
        }
      });
    });

    const isValid =
      (childUnder12.length === 0 || !missingChildCoverage) && (extraAdults === 0 || !missingAdultCoverage);
    if (!isValid) {
      return {
        bedType,
        total: 0,
        surcharges: [],
        matchedAny: false,
        additionalNote: '',
        isValid,
      };
    }

    return {
      bedType,
      total,
      surcharges,
      matchedAny,
      additionalNote: this.buildSurchargeAdditionalNote(surcharges),
      isValid,
    };

