   * @param stayDates - Danh sách các đêm lưu trú
   * @param hotelId - ID khách sạn
   * @param minAdultAge - Tuổi tối thiểu để được coi là người lớn
   * @returns Phụ phí tốt nhất và các tùy chọn phụ phí khác
   */
  private calcSurcharge(
    surcharge: SurchargeCalendarMap,
    guest: HotelSearchRoomDto,
    room: Room,
    mealPlan: MealPlan | null,
    stayDates: HotelRoomStayDate[],
    hotelId: number,
    minAdultAge: number,
  ): { total: number; surcharges: HotelPriceSurcharge[]; surchargeOptions: HotelPriceSurchargeOption[] } {
    if (!stayDates.length) return { total: 0, surcharges: [], surchargeOptions: [] };

    const resolvedMealPlan = mealPlan ?? MealPlan.RO;
    const childAges = guest.children?.map(c => c.age || 0) ?? [];
    // Sort để trẻ lớn ở đầu, trẻ nhỏ ở cuối
    const childUnderAge = childAges.filter(age => age < minAdultAge).sort((a, b) => b - a);
    const adultCount = (guest.adults || 0) + childAges.filter(age => age >= minAdultAge).length;

    // Check vượt sức chứa tối đa
    // Check 1: Tổng khách không vượt maxCapacity
    if (adultCount + childUnderAge.length > room.maxCapacity) return { total: 0, surcharges: [], surchargeOptions: [] };

    // Check 2: Người lớn không vượt maxAdultCapacity
    if (adultCount > room.maxAdultCapacity) return { total: 0, surcharges: [], surchargeOptions: [] };

    // Check 3: Trẻ em có thể chiếm slot người lớn khi còn chỗ trống
    // Số slot người lớn còn trống (tính theo maxAdultCapacity, không phải maxAdults)
    const availableAdultSlots = Math.max(0, room.maxAdultCapacity - adultCount);
    // Số trẻ em vượt quá slot người lớn có sẵn
    const extraChildrenForCapacityCheck = Math.max(0, childUnderAge.length - availableAdultSlots);
    // Chỉ check trẻ em vượt quá với maxChildrenCapacity
    if (extraChildrenForCapacityCheck > room.maxChildrenCapacity) {
      return { total: 0, surcharges: [], surchargeOptions: [] };
    }

    // Tính số người lớn dư (luôn tính phụ thu nếu vượt maxAdults)
    const extraAdults = Math.max(0, adultCount - room.maxAdults);

    // Tính số trẻ con dư cho phụ phí
    // Trẻ em chỉ tính phụ phí khi vượt quá slot người lớn TIÊU CHUẨN (maxAdults)
    const availableSlotsForChildren = Math.max(0, room.maxAdults - adultCount);
    const extraChildrenCount = Math.max(0, childUnderAge.length - availableSlotsForChildren);
    const extraChildren = extraChildrenCount > 0 ? childUnderAge.slice(-extraChildrenCount) : [];

    // Nếu không có người dư cần tính phụ thu
    if (extraAdults === 0 && extraChildren.length === 0) {
      return { total: 0, surcharges: [], surchargeOptions: [] };
    }

    // Calculate surcharges separately for adults and children
    const adultNoBed = this.calcSurchargeByBedType(
      SurchargeBedType.NO_BED,
      extraAdults,
      [],
      resolvedMealPlan,
      stayDates,
      hotelId,
      room.id,
      surcharge,
    );
    const adultExtraBed = this.calcSurchargeByBedType(
      SurchargeBedType.EXTRA_BED,
      extraAdults,
      [],
      resolvedMealPlan,
      stayDates,
      hotelId,
      room.id,
      surcharge,
    );
    const childNoBed = this.calcSurchargeByBedType(
      SurchargeBedType.NO_BED,
      0,
      extraChildren,
      resolvedMealPlan,
      stayDates,
      hotelId,
      room.id,
      surcharge,
    );
    const childExtraBed = this.calcSurchargeByBedType(
      SurchargeBedType.EXTRA_BED,
      0,
      extraChildren,
      resolvedMealPlan,
      stayDates,
      hotelId,
      room.id,
      surcharge,
    );

    // Create combinations
    const combinations = [];

    // Combination 1: Adult NO_BED + Child NO_BED
    if ((extraAdults === 0 || adultNoBed.isValid) && (extraChildren.length === 0 || childNoBed.isValid)) {
      const total = (adultNoBed.total || 0) + (childNoBed.total || 0);
      const notes = [adultNoBed.additionalNote, childNoBed.additionalNote].filter(Boolean).join(' | ');
      combinations.push({
        bedType: 'NO_BED',
        total,
        additionalNote: notes || 'No surcharge',
        isValid: true,
        matchedAny: adultNoBed.matchedAny || childNoBed.matchedAny,
        surcharges: [...(adultNoBed.surcharges || []), ...(childNoBed.surcharges || [])],
      });
    }

    // Combination 2: Adult EXTRA_BED + Child NO_BED (only if there are BOTH extra adults AND extra children)
    if (extraAdults > 0 && extraChildren.length > 0 && adultExtraBed.isValid && childNoBed.isValid) {
      const total = (adultExtraBed.total || 0) + (childNoBed.total || 0);
      const notes = [adultExtraBed.additionalNote, childNoBed.additionalNote].filter(Boolean).join(' | ');
      combinations.push({
        bedType: 'EXTRA_BED_ADULT_NO_BED_CHILD',
        total,
        additionalNote: notes || 'Adult extra bed, child no bed',
        isValid: true,
        matchedAny: adultExtraBed.matchedAny || childNoBed.matchedAny,
        surcharges: [...(adultExtraBed.surcharges || []), ...(childNoBed.surcharges || [])],
      });
    }

    // Combination 3: Adult EXTRA_BED + Child EXTRA_BED
    if (
      (extraAdults === 0 || adultExtraBed.isValid) &&
      (extraChildren.length === 0 || childExtraBed.isValid) &&
      (adultExtraBed.matchedAny || childExtraBed.matchedAny)
    ) {
      const total = (adultExtraBed.total || 0) + (childExtraBed.total || 0);
      const notes = [adultExtraBed.additionalNote, childExtraBed.additionalNote].filter(Boolean).join(' | ');
      combinations.push({
        bedType: 'EXTRA_BED',
        total,
        additionalNote: notes || 'All extra bed',
        isValid: true,
        matchedAny: adultExtraBed.matchedAny || childExtraBed.matchedAny,
        surcharges: [...(adultExtraBed.surcharges || []), ...(childExtraBed.surcharges || [])],
      });
    }

    const surchargeOptions = combinations
