    const candidates = combinations.filter(option => option.isValid && option.matchedAny);
    let selected = candidates[0];
    if (candidates.length > 1) {
      selected = candidates.reduce((best, current) => (current.total < best.total ? current : best), candidates[0]);
    }

    return {
      total: selected ? selected.total : 0,
      surcharges: selected ? selected.surcharges : [],
      surchargeOptions,
    };
  }

