        aggregated.set(key, { label, quantity: item.quantity, total: item.total });
      }
    });

    return Array.from(aggregated.values())
      .map(entry => `${entry.label} x${entry.quantity}: ${entry.total}`)
      .join(' | ');
  }

  /**
   * Chọn surcharge row phù hợp nhất dựa trên điều kiện
   * ƪu tiên row có roomId cụ thể, sau đó lấy row đầu tiên match
   *
   * @param rows - Danh sách surcharge rows
   * @param customerType - Loại khách (ADULT/CHILD)
   * @param isExtraBed - Có phải giường phụ không
   * @param age - Tuổi của khách (optional)
   * @returns Surcharge row phù hợp hoặc undefined
   */
  private selectSurchargeRow(
    rows: SurchargeRateCalendarRow[],
    customerType: CustomerType,
    isExtraBed: boolean,
    age?: number,
  ): SurchargeRateCalendarRow | undefined {
    const filtered = rows.filter(
      row =>
        row.customerType === customerType &&
        this.isExtraBedType(row.type) === isExtraBed &&
        this.matchesAgeRange(row, age),
    );
    if (!filtered.length) return undefined;
    const exact = filtered.find(row => !!row.roomId);
    return exact ?? filtered[0];
  }

